 1→import { Controller, Get, HttpCode, HttpStatus, Query } from '@nestjs/common';
 2→import { ApiOkResponse, ApiOperation, ApiTags } from '@nestjs/swagger';
 3→
 4→import { MarchPromoQueryDto } from '@modules/rest/promos/dto/march-promo-query.dto';
 5→import { PromoQueryDto } from '@modules/rest/promos/dto/promo-query.dto';
 6→import { PromoResponseDto } from '@modules/rest/promos/dto/promo-response.dto';
 7→import { PromosService } from '@modules/rest/promos/promos.service';
 8→
 9→@ApiTags('Promos')
10→@Controller()
11→export class PromosController {
12→	constructor(private readonly promosService: PromosService) {}
13→
14→	@Get('hat-promo')
15→	@HttpCode(HttpStatus.OK)
16→	@ApiOperation({
17→		summary: 'Get hat promo products',
18→		description:
19→			'Returns a 90/10 blend of trending products and promotional products for Hat promo deals (Hats category only), with priority brand boosting (Adidas, Columbia, Imperial, Legacy, Locale, Pukka, Swannies, Under Armour, Vineyard Vines, Core365, Team365).',
20→	})
21→	@ApiOkResponse({
22→		description: 'Successfully retrieved hat promo products',
23→		type: PromoResponseDto,
24→	})
25→	async getHatPromoProducts(@Query() query: PromoQueryDto): Promise<PromoResponseDto> {
26→		return await this.promosService.getHatPromoProducts(query.limit);
27→	}
28→
29→	@Get('march-promo')
30→	@HttpCode(HttpStatus.OK)
31→	@ApiOperation({
32→		summary: 'Get march promo products',
33→		description:
34→			'Returns trending products from a curated list of promotional products, filtered by category. Allowed categories: 218 (Promotional Products), 8 (Pens & Office Supplies), 188 (Technology), 521 (Pens & Writing), 920 (Stationery), 405 (Stickers & Magnets).',
35→	})
36→	@ApiOkResponse({
37→		description: 'Successfully retrieved march promo products',
38→		type: PromoResponseDto,
39→	})
40→	async getMarchPromoProducts(
41→		@Query() query: MarchPromoQueryDto,
42→	): Promise<PromoResponseDto> {
43→		return await this.promosService.getMarchPromoProducts({
44→			limit: query.limit,
45→			categoryId: query.categoryId,
46→		});
47→	}
48→}
