  1→import { Injectable, Logger } from '@nestjs/common';
  2→
  3→import { ForecastedTrendingProductsService } from '@modules/db/forecasted-trending-products/forecasted-trending-products.service';
  4→import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
  5→import { PromoResponseDto } from '@modules/rest/promos/dto/promo-response.dto';
  6→
  7→import { shuffleArray } from '@utils/array.util';
  8→import { assignRandomColorToProduct } from '@utils/random-color-picker.util';
  9→
 10→import { IRelatedProduct } from '@interfaces/related-product.interface';
 11→
 12→import { LogExecution } from '@decorators/log-execution.decorator';
 13→
 14→@Injectable()
 15→export class PromosService {
 16→	private readonly logger = new Logger(PromosService.name);
 17→
 18→	private readonly HAT_PROMO_BRANDS = [
 19→		'Adidas',
 20→		'Columbia',
 21→		'Imperial',
 22→		'Legacy',
 23→		'Locale',
 24→		'Pukka',
 25→		'Swannies',
 26→		'Under Armour',
 27→		'Vineyard Vines',
 28→		'Core365',
 29→		'Team365',
 30→	];
 31→
 32→	private readonly HAT_CATEGORY_ID = 1;
 33→
 34→	private readonly MARCH_PROMO_DEFAULT_CATEGORY_ID = 8;
 35→
 36→	private readonly MARCH_PROMO_PRODUCT_IDS = [
 37→		349500, 891500, 264200, 1490500, 1557200, 354400, 268900, 947400, 1239000, 1513400,
 38→		661300, 817300, 882800, 268500, 264100, 872300, 965200, 1132700, 818200, 1196100,
 39→		268600, 103700, 370800, 1196500, 647600, 275800, 883000, 1540500, 1585800, 1720600,
 40→		1718500, 661200, 1501700, 818300, 1618200, 873100, 835600, 1523000, 1120800, 1184200,
 41→		1565500, 1617900, 350100, 1692900, 1163800, 1842500, 1565600, 1587800, 1885900,
 42→		1630500, 1687400, 1686400, 1686300, 1863900, 1556600, 1192100, 1609500, 349800,
 43→		2654000, 2622600, 2727700,
 44→	];
 45→
 46→	private readonly BRAND_PERCENTAGE = 0.3;
 47→
 48→	constructor(
 49→		private readonly forecastedTrendingProductsService: ForecastedTrendingProductsService,
 50→		private readonly productHydrationService: ProductHydrationService,
 51→	) {}
 52→
 53→	@LogExecution({
 54→		paramFormatter: ([limit]: [number]) => ({ limit }),
 55→		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
 56→			totalCount: res.totalCount,
 57→			trendingCount: res.trendingCount,
 58→			boostedBrandCount: res.boostedBrandCount,
 59→		}),
 60→	})
 61→	async getHatPromoProducts(limit = 20): Promise<PromoResponseDto> {
 62→		try {
 63→			const [trendingData, brandResult] = await Promise.all([
 64→				this.forecastedTrendingProductsService.getTrendingProductsByCategory({
 65→					categoryId: this.HAT_CATEGORY_ID,
 66→					limit: 100,
 67→				}),
 68→				this.productHydrationService.getProductsByBrands({
 69→					brands: this.HAT_PROMO_BRANDS,
 70→					limit: 100,
 71→					categoryId: this.HAT_CATEGORY_ID,
 72→				}),
 73→			]);
 74→
 75→			const trendingIds = trendingData.map((p) => p.style_id);
 76→
 77→			const { products: hydratedProducts, mvRecords } =
 78→				await this.productHydrationService.hydrateProductsWithColors({
 79→					styleIds: trendingIds,
 80→				});
 81→
 82→			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));
 83→
 84→			const trendingProducts: IRelatedProduct[] = [];
 85→			const brandProducts: IRelatedProduct[] = [];
 86→
 87→			for (const trending of trendingData) {
 88→				const product = productsByStyleId.get(trending.style_id);
 89→				if (product) {
 90→					const mv = mvRecords.get(trending.style_id);
 91→					const colors = this.productHydrationService.convertMvColorsToProductColors({
 92→						colors: mv?.colors ?? null,
 93→					});
 94→					const productWithRandomColor = assignRandomColorToProduct({
 95→						product,
 96→						availableColors: colors,
 97→					});
 98→					trendingProducts.push(productWithRandomColor);
 99→				}
100→			}
101→
102→			for (const product of brandResult.products) {
103→				const mv = brandResult.mvRecords.get(product.style_id);
104→				const colors = this.productHydrationService.convertMvColorsToProductColors({
105→					colors: mv?.colors ?? null,
106→				});
107→				const productWithRandomColor = assignRandomColorToProduct({
108→					product,
109→					availableColors: colors,
110→				});
111→				brandProducts.push(productWithRandomColor);
112→			}
113→
114→			this.logger.debug(
115→				`Verified ${trendingProducts.length} trending products, ${brandProducts.length} brand products`,
116→			);
117→
118→			const brandProductSet = new Set(brandProducts.map((p) => p.style_id));
119→
120→			const nonBrandTrending = trendingProducts.filter(
121→				(p) => !brandProductSet.has(p.style_id),
122→			);
123→
124→			const targetBrandCount = Math.min(
125→				brandProducts.length,
126→				Math.floor(limit * this.BRAND_PERCENTAGE),
127→			);
128→			const selectedBrands = shuffleArray({ array: brandProducts }).slice(
129→				0,
130→				targetBrandCount,
131→			);
132→
133→			const selectedTrending = shuffleArray({ array: nonBrandTrending }).slice(
134→				0,
135→				Math.max(0, limit - selectedBrands.length),
136→			);
137→
138→			const allProducts = [...selectedTrending, ...selectedBrands];
139→			const finalProducts = shuffleArray({ array: allProducts }).slice(0, limit);
140→
141→			return {
142→				products: finalProducts,
143→				totalCount: finalProducts.length,
144→				trendingCount: selectedTrending.length + selectedBrands.length,
145→				promotionalCount: 0,
146→				boostedBrandCount: selectedBrands.length,
147→			};
148→		} catch (error) {
149→			this.logger.error(`Error fetching hat promo products: ${(error as Error).message}`);
150→			throw error;
151→		}
152→	}
153→
154→	@LogExecution({
155→		paramFormatter: /* istanbul ignore next */ ([params]: [
156→			{ limit: number; categoryId: number }?,
157→		]) => ({
158→			limit: params?.limit,
159→			categoryId: params?.categoryId,
160→		}),
161→		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
162→			totalCount: res.totalCount,
163→			trendingCount: res.trendingCount,
164→		}),
165→	})
166→	async getMarchPromoProducts({
167→		limit = 20,
168→		categoryId = this.MARCH_PROMO_DEFAULT_CATEGORY_ID,
169→	}: {
170→		limit?: number | undefined;
171→		categoryId?: number | undefined;
172→	} = {}): Promise<PromoResponseDto> {
173→		try {
174→			const trendingData =
175→				await this.forecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds(
176→					{
177→						categoryId,
178→						styleIds: this.MARCH_PROMO_PRODUCT_IDS,
179→						limit: 100,
180→					},
181→				);
182→
183→			const styleIds = trendingData.map((p) => p.style_id);
184→
185→			const { products: hydratedProducts, mvRecords } =
186→				await this.productHydrationService.hydrateProductsWithColors({ styleIds });
187→
188→			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));
189→
190→			const trendingProducts: IRelatedProduct[] = [];
191→
192→			for (const trending of trendingData) {
193→				const product = productsByStyleId.get(trending.style_id);
194→				if (product) {
195→					const mv = mvRecords.get(trending.style_id);
196→					const colors = this.productHydrationService.convertMvColorsToProductColors({
197→						colors: mv?.colors ?? null,
198→					});
199→					const productWithRandomColor = assignRandomColorToProduct({
200→						product,
201→						availableColors: colors,
202→					});
203→					trendingProducts.push(productWithRandomColor);
204→				}
205→			}
206→
207→			const finalProducts = trendingProducts.slice(0, limit);
208→
209→			return {
210→				products: finalProducts,
211→				totalCount: finalProducts.length,
212→				trendingCount: finalProducts.length,
213→				promotionalCount: 0,
214→				boostedBrandCount: 0,
215→			};
216→		} catch (error) {
217→			this.logger.error(
218→				`Error fetching march promo products: ${(error as Error).message}`,
219→			);
220→			throw error;
221→		}
222→	}
223→}
