 1→import { ApiPropertyOptional } from '@nestjs/swagger';
 2→import { Type } from 'class-transformer';
 3→import { IsInt, IsOptional, Min } from 'class-validator';
 4→
 5→export class PromoQueryDto {
 6→	@ApiPropertyOptional({
 7→		description: 'Number of products to return',
 8→		example: 20,
 9→		default: 20,
10→	})
11→	@IsOptional()
12→	@Type(() => Number)
13→	@IsInt({ message: 'Limit must be an integer' })
14→	@Min(1, { message: 'Limit must be greater than 0' })
15→	limit?: number;
16→}
